import React from 'react';
import { Card, Stack, Text, Box, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city?: string;
  /** Current temperature */
  temperature?: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition?: string;
  /** Humidity percentage */
  humidity?: number;
  /** Wind speed */
  windSpeed?: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast?: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * Helper function to map condition strings to emoji.
 * Can be extended with more conditions as needed.
 */
function getWeatherEmoji(condition: string): string {
  const conditionLower = condition.toLowerCase();

  if (
    conditionLower.includes('sunny') ||
    conditionLower.includes('clear')
  ) {
    return '☀️';
  } else if (conditionLower.includes('cloud')) {
    return '☁️';
  } else if (
    conditionLower.includes('rain') ||
    conditionLower.includes('rainy')
  ) {
    return '🌧️';
  } else if (conditionLower.includes('snow')) {
    return '❄️';
  } else if (conditionLower.includes('thunder')) {
    return '⛈️';
  } else if (conditionLower.includes('wind')) {
    return '💨';
  } else if (conditionLower.includes('fog')) {
    return '🌫️';
  } else if (conditionLower.includes('haze')) {
    return '🌫️';
  } else {
    return '🌤️'; // Default to partly cloudy
  }
}

export default function WeatherCard({
