  temperature = 20,
  condition = 'Clear',
  humidity = 50,
  windSpeed = 10,
  unit = '°C',
  forecast = [
    { day: '—', icon: '—', high: 0, low: 0 },
    { day: '—', icon: '—', high: 0, low: 0 },
    { day: '—', icon: '—', high: 0, low: 0 },
    { day: '—', icon: '—', high: 0, low: 0 },
    { day: '—', icon: '—', high: 0, low: 0 },
