  return (
    <Card
      padding="24"
      shadow="md"
      border={true}
      style={{
        backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
    >
      <Stack direction="vertical" gap={20}>
        {/* Header: City and Condition */}
        <Stack
          direction="horizontal"
          justify="between"
          align="center"
          gap={16}
        >
          <Stack direction="vertical" gap={4}>
            <Text
              variant="h3"
              weight="semibold"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {city}
            </Text>
            <Text
              variant="body"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              {condition}
            </Text>
          </Stack>

          {/* Condition Emoji/Icon */}
          <Box
            padding="12"
            borderRadius="12"
            style={{
              backgroundColor: 'var(--ggui-color-primary-100, #e0f2fe)',
              border: '2px solid var(--ggui-color-primary-200, #bae6fd)',
              fontSize: '32px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              minWidth: '60px',
              height: '60px',
            }}
          >
            {/* Use emoji or icon from condition prop if available */}
            {getWeatherEmoji(condition)}
          </Box>
        </Stack>

        {/* Large Temperature Display */}
        <div
          style={{
            textAlign: 'center',
            padding: 'var(--ggui-spacing-4, 16px) 0',
          }}
        >
          <Text
            variant="h1"
            weight="bold"
            color="var(--ggui-color-primary-600, #0284c7)"
            style={{
              fontSize: 'var(--ggui-font-size-4xl, 36px)',
              lineHeight: '1.2',
            }}
          >
            {temperature}{unit}
          </Text>
        </div>

        {/* Metrics: Humidity and Wind Speed */}
        <Stack
          direction="horizontal"
          justify="between"
          align="center"
          gap={24}
        >
          {/* Humidity */}
          <Stack direction="vertical" gap={4} align="start">
            <Text
              variant="label"
              weight="medium"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Humidity
            </Text>
            <Text
              variant="body"
              weight="semibold"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {humidity}%
            </Text>
          </Stack>

          {/* Wind Speed */}
          <Stack direction="vertical" gap={4} align="start">
            <Text
              variant="label"
              weight="medium"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Wind Speed
            </Text>
            <Text
              variant="body"
              weight="semibold"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {windSpeed} km/h
            </Text>
          </Stack>
        </Stack>

        {/* Divider before forecast */}
        <Divider
          orientation="horizontal"
          margin={16}
          style={{
            borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
          }}
        />

        {/* 5-Day Forecast Strip */}
        <Stack direction="vertical" gap={8}>
          <Text
            variant="label"
            weight="semibold"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            5-Day Forecast
          </Text>

          <Stack
            direction="horizontal"
            gap={12}
            justify="start"
            wrap={true}
            style={{
              overflowX: 'auto',
              paddingBottom: 'var(--ggui-spacing-2, 8px)',
            }}
          >
            {forecast && forecast.length > 0
              ? forecast.map((item, index) => (
                  <Card
                    key={index}
                    padding="12"
                    shadow="none"
                    border={true}
                    style={{
                      borderColor:
                        'var(--ggui-color-outlineVariant, #e4e4e7)',
                      backgroundColor:
                        'var(--ggui-color-surface, #fafafa)',
                      flex: '0 0 auto',
                      minWidth: '80px',
                    }}
                  >
                    <Stack
                      direction="vertical"
                      align="center"
                      gap={4}
                      style={{
                        textAlign: 'center',
                      }}
                    >
                      {/* Day name */}
                      <Text
                        variant="caption"
                        weight="medium"
                        color="var(--ggui-color-onSurface, #18181b)"
                      >
                        {item.day || '—'}
                      </Text>

                      {/* Weather icon/emoji */}
                      <div
                        style={{
                          fontSize: '24px',
                          minHeight: '28px',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                        }}
                      >
                        {item.icon || '—'}
                      </div>

                      {/* High temperature */}
                      <Text
                        variant="caption"
                        weight="medium"
                        color="var(--ggui-color-onSurface, #18181b)"
                      >
                        {item.high || 0}°
                      </Text>

                      {/* Low temperature */}
                      <Text
                        variant="caption"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      >
                        {item.low || 0}°
                      </Text>
                    </Stack>
                  </Card>
                ))
              : null}
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
}

import { useState } from 'react';
import { Container, Card, Stack, Row, Text, Input, TextArea, Button, RadioGroup, Checkbox, Divider, Badge, Icon } from '@ggui-ai/design/primitives';

interface FormData {
  name: string;
  email: string;
  satisfaction: string;
  features: string[];
  comments: string;
}

interface Props {
  featureOptions?: string[];
  satisfactionLabels?: string[];
  onSubmit?: (data: FormData) => void;
}

interface ValidationErrors {
  name?: string;
  email?: string;
  satisfaction?: string;
  features?: string;
  comments?: string;
}

export default function MultiStepSurveyForm({ featureOptions = ['Feature A', 'Feature B', 'Feature C', 'Feature D', 'Feature E'], satisfactionLabels = ['Very Unsatisfied', 'Unsatisfied', 'Neutral', 'Satisfied', 'Very Satisfied'], onSubmit }: Props) {
  const [currentStep, setCurrentStep] = useState(0);
  const [formData, setFormData] = useState<FormData>({ name: '', email: '', satisfaction: '', features: [], comments: '' });
  const [errors, setErrors] = useState<ValidationErrors>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitStatus, setSubmitStatus] = useState<'idle' | 'success' | 'error'>('idle');
  const [submitError, setSubmitError] = useState('');

  const TOTAL_STEPS = 4;
  const STEPS_TITLES = ['Your Information', 'Satisfaction Rating', 'Feature Interests', 'Additional Comments'];

  const validateName = (value: string): string => { if (!value.trim()) return 'Name is required'; if (value.trim().length < 2) return 'Name must be at least 2 characters'; return ''; };
  const validateEmail = (value: string): string => { if (!value.trim()) return 'Email is required'; if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value)) return 'Please enter a valid email address'; return ''; };

  const validateStep = (stepIndex: number): boolean => {
    const newErrors: ValidationErrors = {};
    if (stepIndex === 0) { newErrors.name = validateName(formData.name); newErrors.email = validateEmail(formData.email); } else if (stepIndex === 1) { if (!formData.satisfaction) newErrors.satisfaction = 'Please select a satisfaction rating'; }
    setErrors(newErrors);
    return Object.values(newErrors).every((err) => !err);
  };

  const handleInputChange = (field: keyof FormData, value: string | string[]) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    if (field === 'name') { const error = validateName(value as string); setErrors((prev) => ({ ...prev, name: error })); } else if (field === 'email') { const error = validateEmail(value as string); setErrors((prev) => ({ ...prev, email: error })); } else if (field === 'satisfaction') { if (value) setErrors((prev) => ({ ...prev, satisfaction: '' })); }
  };

  const handleFeatureToggle = (feature: string, checked: boolean) => { setFormData((prev) => ({ ...prev, features: checked ? [...prev.features, feature] : prev.features.filter((f) => f !== feature) })); };
  const handleNext = () => { if (!validateStep(currentStep)) return; if (currentStep < TOTAL_STEPS) setCurrentStep((prev) => prev + 1); };
  const handleBack = () => { if (currentStep > 0) { setCurrentStep((prev) => prev - 1); setSubmitStatus('idle'); } };

  const handleSubmit = async () => {
    if (!validateStep(0)) return; if (!formData.satisfaction) { setErrors((prev) => ({ ...prev, satisfaction: 'Please select a satisfaction rating' })); return; }
    setIsSubmitting(true); setSubmitStatus('idle'); setSubmitError('');
    try { await new Promise((resolve) => setTimeout(resolve, 1000)); const submitData: FormData = { name: formData.name, email: formData.email, satisfaction: formData.satisfaction, features: formData.features, comments: formData.comments };
      if (onSubmit) onSubmit(submitData);
      setSubmitStatus('success');
      setTimeout(() => { setFormData({ name: '', email: '', satisfaction: '', features: [], comments: '' }); setCurrentStep(0); setSubmitStatus('idle'); }, 2000);
    } catch (err) { setSubmitStatus('error'); setSubmitError(err instanceof Error ? err.message : 'Failed to submit survey'); } finally { setIsSubmitting(false); }
  };

  const buildSatisfactionLabel = (index: number, label: string): string => { const num = String(index + 1); return num + ' - ' + label; };
  const satisfactionOptions = satisfactionLabels.map((label, idx) => ({ value: String(idx + 1), label: buildSatisfactionLabel(idx, label) }));

  const renderStep0 = () => (
    <Stack direction="vertical" gap={16}>
      <Text variant="h3">{STEPS_TITLES[0]}</Text>
      <Stack direction="vertical" gap={8}>
        <Text as="label" htmlFor="inputName">Full Name</Text>
        <Input id="inputName" label="Full Name" placeholder="Enter your full name" value={formData.name} onChange={(value) => handleInputChange('name', value)} error={errors.name} required />
      </Stack>
      <Stack direction="vertical" gap={8}>
        <Text as="label" htmlFor="inputEmail">Email Address</Text>
        <Input id="inputEmail" label="Email Address" type="email" placeholder="you@example.com" value={formData.email} onChange={(value) => handleInputChange('email', value)} error={errors.email} required />
      </Stack>
    </Stack>
  );

  const renderStep1 = () => (
    <Stack direction="vertical" gap={16}>
      <Text variant="h3">{STEPS_TITLES[1]}</Text>
      <RadioGroup label="How satisfied are you with our service?" value={formData.satisfaction} onChange={(value) => handleInputChange('satisfaction', value)} options={satisfactionOptions} direction="vertical" error={errors.satisfaction} />
    </Stack>
  );

  const renderStep2 = () => (
    <Stack direction="vertical" gap={16}>
      <Text variant="h3">{STEPS_TITLES[2]}</Text>
      <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">Which features are you interested in?</Text>
      <Stack direction="vertical" gap={12} role="group">
        {featureOptions.map((feature) => (
          <Checkbox key={feature} label={feature} checked={formData.features.includes(feature)} onChange={(checked) => handleFeatureToggle(feature, checked)} />
        ))}
      </Stack>
    </Stack>
  );

  const renderStep3 = () => (
    <Stack direction="vertical" gap={16}>
      <Text variant="h3">{STEPS_TITLES[3]}</Text>
      <Stack direction="vertical" gap={8}>
        <Text as="label" htmlFor="inputComments">Additional Comments</Text>
        <TextArea id="inputComments" label="Additional Comments" placeholder="Share your thoughts, suggestions, or feedback (optional)" value={formData.comments} onChange={(value) => handleInputChange('comments', value)} rows={4} maxLength={500} helperText={formData.comments.length + ' / 500 characters'} />
      </Stack>
    </Stack>
  );

  const renderStep4 = () => (
    <Stack direction="vertical" gap={20}>
      <Text variant="h3">Review Your Answers</Text>
      <Divider margin={16} />
      <Stack direction="vertical" gap={12}>
        <Row><Text variant="label" weight="semibold">Name:</Text><Text>{formData.name}</Text></Row>
        <Row><Text variant="label" weight="semibold">Email:</Text><Text>{formData.email}</Text></Row>
        <Row><Text variant="label" weight="semibold">Satisfaction:</Text><Text>{satisfactionLabels[parseInt(formData.satisfaction) - 1]}</Text></Row>
        <Row><Text variant="label" weight="semibold">Features of Interest:</Text><Text>{formData.features.length > 0 ? formData.features.join(', ') : 'None selected'}</Text></Row>
        {formData.comments && (<Row><Text variant="label" weight="semibold">Comments:</Text><Text>{formData.comments}</Text></Row>)}
      </Stack>
      <Divider margin={16} />
      {submitStatus === 'success' && (
        <Stack direction="horizontal" gap={8} align="center" style={{ padding: 'var(--ggui-spacing-4)', backgroundColor: 'var(--ggui-color-success-500)', borderRadius: 'var(--ggui-shape-radius-md)' }} role="status">
          <Icon name="check" size={20} color="var(--ggui-color-onSuccess)" />
          <Text color="var(--ggui-color-onSuccess)" weight="medium">Survey submitted successfully!</Text>
        </Stack>
      )}
      {submitStatus === 'error' && (
        <Stack direction="vertical" gap={8} style={{ padding: 'var(--ggui-spacing-4)', backgroundColor: 'var(--ggui-color-error-500)', borderRadius: 'var(--ggui-shape-radius-md)' }} role="alert">
          <Text color="var(--ggui-color-onError)" weight="medium">Error submitting survey</Text>
          {submitError && (<Text color="var(--ggui-color-onError)" variant="caption">{submitError}</Text>)}
        </Stack>
      )}
    </Stack>
  );

  const renderStepContent = () => {
    switch (currentStep) {
      case 0: return renderStep0();
      case 1: return renderStep1();
      case 2: return renderStep2();
      case 3: return renderStep3();
      case 4: return renderStep4();
      default: return null;
    }
  };

  const isCurrentStepValid = currentStep === 0 ? !errors.name && !errors.email && formData.name && formData.email : currentStep === 1 ? formData.satisfaction && !errors.satisfaction : true;

  return (
    <Container maxWidth="md" padding={24} center>
      <Card padding={24} shadow="md">
        <Stack direction="vertical" gap={24} role="form" aria-label="Multi-step survey form">
          <Stack direction="vertical" gap={12}>
            <Row justify="between" align="center">
              <Text variant="h2">Survey Form</Text>
              <Badge variant="info">Step {currentStep + 1} of {TOTAL_STEPS + 1}</Badge>
            </Row>
            <div style={{ width: '100%', height: 8, backgroundColor: 'var(--ggui-color-outlineVariant)', borderRadius: 'var(--ggui-shape-radius-full)', overflow: 'hidden' }} role="progressbar" aria-valuenow={currentStep + 1} aria-valuemin={1} aria-valuemax={TOTAL_STEPS + 1}>
              <div style={{ height: '100%', width: (((currentStep + 1) / (TOTAL_STEPS + 1)) * 100) + '%', backgroundColor: 'var(--ggui-color-primary-600)', borderRadius: 'var(--ggui-shape-radius-full)', transition: 'width 300ms ease-out' }} />
            </div>
          </Stack>
          <Divider margin={16} />
          {renderStepContent()}
          <Divider margin={16} />
          <Row justify="between" gap={12}>
            {currentStep > 0 ? (<Button variant="outline" onClick={handleBack} disabled={isSubmitting}>Back</Button>) : (<div />)}
            {currentStep < TOTAL_STEPS ? (<Button variant="primary" onClick={handleNext} disabled={!isCurrentStepValid || isSubmitting}>Next</Button>) : (<Button variant="primary" onClick={handleSubmit} disabled={isSubmitting} loading={isSubmitting}>{isSubmitting ? 'Submitting...' : 'Submit Survey'}</Button>)}
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

import { Card, Stack, Row, Text, Box, Divider, Badge, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

function getConditionEmoji(condition: string): string {
  const lower = condition.toLowerCase();
  if (lower.includes('sunny') || lower.includes('clear')) return '☀️';
  if (lower.includes('partly cloudy')) return '⛅';
  if (lower.includes('cloudy') || lower.includes('overcast')) return '☁️';
  if (lower.includes('rain')) return '🌧️';
  if (lower.includes('storm') || lower.includes('thunder')) return '⛈️';
  if (lower.includes('snow')) return '🌨️';
  if (lower.includes('fog') || lower.includes('mist')) return '🌫️';
  if (lower.includes('wind')) return '💨';
  return '🌡️';
}

export default function GeneratedComponent({
  city = 'San Francisco',
  temperature = 72,
  condition = 'Sunny',
  humidity = 45,
  windSpeed = 12,
  unit = 'F',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 74, low: 58 },
    { day: 'Tue', icon: '⛅', high: 70, low: 56 },
    { day: 'Wed', icon: '🌧️', high: 65, low: 52 },
    { day: 'Thu', icon: '🌤️', high: 68, low: 54 },
    { day: 'Fri', icon: '☀️', high: 75, low: 60 },
  ],
}: Props) {
  const { motionEnabled } = useMotion();
  const conditionEmoji = getConditionEmoji(condition);
  const speedUnit = unit === 'C' ? 'km/h' : 'mph';
  const unitLabel = unit === 'C' ? 'Celsius' : 'Fahrenheit';
  const windUnitLabel = unit === 'C' ? 'kilometers' : 'miles';

  return (
    <>
      <MotionKeyframes />
      <div
        role="region"
        aria-label={'Weather for ' + city}
        style={{
          maxWidth: 420,
          width: '100%',
          animation: motionEnabled ? animation.fadeIn : 'none',
        }}
      >
        <Card shadow="md" border={true} padding={0}>
          <Stack direction="vertical" gap={0}>

            {/* ── HEADER: Gradient with city, condition, temperature ── */}
            <Box
              padding={0}
              background="linear-gradient(135deg, var(--ggui-color-primary-500, #0ea5e9), var(--ggui-color-primary-700, #0369a1))"
              borderRadius="var(--ggui-shape-radius-md, 8px) var(--ggui-shape-radius-md, 8px) 0 0"
            >
              <div style={{ padding: 'var(--ggui-spacing-6, 24px)' }}>
                <Row justify="between" align="start">
                  <Stack direction="vertical" gap={8} align="start">
                    <Text variant="h3" color="var(--ggui-color-onPrimary, #ffffff)" weight="semibold">
                      {city}
                    </Text>
                    <Badge variant="primary" size="sm" pill={true}>
                      <span aria-hidden="true">{conditionEmoji}</span>{' '}
                      {condition}
                    </Badge>
                  </Stack>

                  <Stack direction="vertical" align="end" gap={2}>
                    <span
                      aria-label={temperature + ' degrees ' + unitLabel}
                      style={{
                        fontSize: 56,
                        fontWeight: 'var(--ggui-font-weight-bold, 700)' as React.CSSProperties['fontWeight'],
                        lineHeight: 1,
                        letterSpacing: '-0.025em',
                        color: 'var(--ggui-color-onPrimary, #ffffff)',
                        display: 'block',
                      }}
                    >
                      {temperature}°{unit}
                    </span>
                  </Stack>
                </Row>
              </div>
            </Box>

            {/* ── STATS: Humidity & Wind ── */}
            <Box
              padding={0}
              background="var(--ggui-color-surface, #fafafa)"
            >
              <div
                style={{
                  padding: 'var(--ggui-spacing-4, 16px) var(--ggui-spacing-6, 24px)',
                }}
              >
                <Row justify="around" align="center" gap={16}>
                  <Stack direction="vertical" align="center" gap={4}>
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    >
                      Humidity
                    </Text>
                    <span
                      aria-label={'Humidity ' + humidity + ' percent'}
                      style={{
                        fontSize: 'var(--ggui-font-size-base, 16px)',
                        fontWeight: 'var(--ggui-font-weight-semibold, 600)' as React.CSSProperties['fontWeight'],
                        color: 'var(--ggui-color-onSurface, #18181b)',
                        display: 'flex',
                        alignItems: 'center',
                        gap: 4,
                      }}
                    >
                      <span aria-hidden="true">💧</span>
                      {humidity}%
                    </span>
                  </Stack>

                  {/* Vertical divider */}
                  <div
                    style={{
                      width: 1,
                      height: 40,
                      background: 'var(--ggui-color-outline, #d4d4d8)',
                      flexShrink: 0,
                    }}
                    aria-hidden="true"
                  />

                  <Stack direction="vertical" align="center" gap={4}>
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    >
                      Wind
                    </Text>
                    <span
                      aria-label={'Wind speed ' + windSpeed + ' ' + windUnitLabel + ' per hour'}
                      style={{
                        fontSize: 'var(--ggui-font-size-base, 16px)',
                        fontWeight: 'var(--ggui-font-weight-semibold, 600)' as React.CSSProperties['fontWeight'],
                        color: 'var(--ggui-color-onSurface, #18181b)',
                        display: 'flex',
                        alignItems: 'center',
                        gap: 4,
                      }}
                    >
                      <span aria-hidden="true">💨</span>
                      {windSpeed} {speedUnit}
                    </span>
                  </Stack>
                </Row>
              </div>
            </Box>

            {/* ── DIVIDER ── */}
            <Divider margin={0} />

            {/* ── FORECAST STRIP ── */}
            <Box
              padding={0}
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
              borderRadius="0 0 var(--ggui-shape-radius-md, 8px) var(--ggui-shape-radius-md, 8px)"
            >
              <div
                style={{ padding: 'var(--ggui-spacing-4, 16px)' }}
                aria-label="5-day weather forecast"
                role="list"
              >
                <Stack direction="vertical" gap={8}>
                  <Text
                    variant="label"
                    weight="semibold"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    5-Day Forecast
                  </Text>

                  <Row justify="between" align="center" gap={4}>
                    {forecast.map((item, index) => (
                      <div
                        key={item.day ?? index}
                        role="listitem"
                        aria-label={(item.day ?? 'Day') + ': high ' + (item.high ?? 'unknown') + '°, low ' + (item.low ?? 'unknown') + '°'}
                      >
                        <Stack direction="vertical" align="center" gap={4}>
                          <Text
                            variant="caption"
                            weight="medium"
                            color="var(--ggui-color-onSurfaceVariant, #52525b)"
                          >
                            {item.day ?? '—'}
                          </Text>
                          <span
                            aria-hidden="true"
                            style={{ fontSize: 24, lineHeight: 1, display: 'block' }}
                          >
                            {item.icon ?? '🌡️'}
                          </span>
                          <Text
                            variant="caption"
                            weight="semibold"
                            color="var(--ggui-color-onSurface, #18181b)"
                          >
                            {item.high != null ? item.high + '°' : '—'}
                          </Text>
                          <Text
                            variant="caption"
                            color="var(--ggui-color-onSurfaceVariant, #52525b)"
                          >
                            {item.low != null ? item.low + '°' : '—'}
                          </Text>
                        </Stack>
                      </div>
                    ))}
                  </Row>
                </Stack>
              </div>
            </Box>

          </Stack>
        </Card>
      </div>
    </>
  );
}

