function buildAriaLabel(el: Props['elements'][number]): string {
  const name = el.name || 'Unknown';
  const num = el.atomicNumber != null ? String(el.atomicNumber) : 'unknown';
  const sym = el.symbol || 'unknown';
  return name + ', atomic number ' + num + ', symbol ' + sym;
}

