  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][number] | null>(null);
  const { motionEnabled } = useMotion();

  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return elements;
    const query = searchQuery.trim().toLowerCase();
    return elements.filter(
      (el) =>
        (el.name && el.name.toLowerCase().includes(query)) ||
        (el.symbol && el.symbol.toLowerCase().includes(query))
    );
  }, [elements, searchQuery]);

  const visibleSet = useMemo(() => {
    return new Set(filteredElements.map((el) => el.atomicNumber));
  }, [filteredElements]);

  const handleElementClick = (el: Props['elements'][number]) => {
    setSelectedElement((prev) =>
      prev && prev.atomicNumber === el.atomicNumber ? null : el
    );
  };

  const handleElementKeyDown = (e: React.KeyboardEvent, el: Props['elements'][number]) => {
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      handleElementClick(el);
    }
