            {elements.map((el) => {
              const isVisible = visibleSet.has(el.atomicNumber);
              const isSelected = selectedElement?.atomicNumber === el.atomicNumber;
              const bgColor = categoryColorMap[el.category || ''] || 'var(--ggui-color-neutral-100, #f3f4f6)';
