                      <span style={{ fontSize: 'var(--ggui-font-size-2xl, 28px)', fontWeight: 'var(--ggui-font-weight-bold, 700)', color: categoryTextColorMap[selectedElement.category || ''] || 'var(--ggui-color-onSurface, #18181b)', lineHeight: 1 }}>
