import { useState, useEffect, useRef, useCallback } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Badge,
  Input,
  Button,
  Icon,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface MessageItem {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Array<MessageItem>;
  onAction?: (action: string, payload: Record<string, unknown>) => void;
}

function formatTimestamp(iso?: string): string {
  if (!iso) return '';
  try {
    return new Date(iso).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  } catch {
    return '';
  }
}

function getBubbleRadius(isOwn: boolean, isFirst: boolean, isLast: boolean): string {
  const lg = 'var(--ggui-shape-radius-lg, 16px)';
  const sm = 'var(--ggui-shape-radius-sm, 4px)';
  if (isFirst && isLast) return lg;
  const parts = isOwn
    ? [lg, isFirst ? lg : sm, isLast ? lg : sm, lg]
    : [isFirst ? lg : sm, lg, lg, isFirst ? sm : lg];
  return parts.join(' ');
}

export default function GeneratedComponent(props: Props) {
  const {
    title = 'Chat Room',
    currentUser = 'You',
    participantCount = 3,
    messages = [
      { sender: 'Alice', text: 'Hey everyone! How are you doing today?', timestamp: '2024-01-15T10:00:00Z' },
      { sender: 'Alice', text: 'I just finished the new design mockups.',  timestamp: '2024-01-15T10:00:30Z' },
      { sender: 'You',   text: 'That sounds great! Can you share them?',   timestamp: '2024-01-15T10:01:00Z' },
      { sender: 'Bob',   text: "I'd love to see them too!",                timestamp: '2024-01-15T10:02:00Z' },
      { sender: 'You',   text: "Let's schedule a review meeting.",          timestamp: '2024-01-15T10:03:00Z' },
    ],
    onAction,
  } = props;

  const [inputValue, setInputValue] = useState('');
  const [streamMessages, setStreamMessages] = useState<MessageItem[]>([]);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputId = 'chat-compose-input';
  const { motionEnabled } = useMotion();

  const allMessages = [...messages, ...streamMessages];

  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  useEffect(() => { scrollToBottom(); }, [allMessages.length, scrollToBottom]);

  // Stream Contract
  useEffect(() => {
    const target = globalThis as unknown as EventTarget;
    const handler = (e: Event) => {
      const detail = (e as CustomEvent).detail;
      if (detail) setStreamMessages((prev) => [...prev, detail as MessageItem]);
    };
    target.addEventListener('ggui:agent-data', handler);
    return () => target.removeEventListener('ggui:agent-data', handler);
  }, []);

  // Action Contract
  const handleSend = useCallback(() => {
    const trimmed = inputValue.trim();
    if (!trimmed) return;
    const payload = { text: trimmed, timestamp: new Date().toISOString() };
    if (onAction) onAction('sendMessage', payload);
    setStreamMessages((prev) => [
      ...prev,
      { sender: currentUser, text: trimmed, timestamp: payload.timestamp },
    ]);
    setInputValue('');
  }, [inputValue, currentUser, onAction]);

  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend(); }
  }, [handleSend]);

  const isSendDisabled = inputValue.trim() === '';

  const renderMessages = () =>
    allMessages.map((msg, index) => {
      const isOwn   = msg.sender === currentUser;
      const prev    = index > 0 ? allMessages[index - 1] : null;
      const next    = index < allMessages.length - 1 ? allMessages[index + 1] : null;
      const isFirst = !prev || prev.sender !== msg.sender;
      const isLast  = !next || next.sender !== msg.sender;
      const bubbleRadius = getBubbleRadius(isOwn, isFirst, isLast);
      const ownText      = 'var(--ggui-color-onPrimary, #ffffff)';
      const ownTimestamp = 'var(--ggui-color-onPrimary-muted, var(--ggui-color-onPrimary, #ffffff))';

      return (
        <div
          key={String(index) + '-' + (msg.timestamp ?? '')}
          style={{
            display: 'flex',
            flexDirection: 'column',
            alignItems: isOwn ? 'flex-end' : 'flex-start',
            marginTop: isFirst ? 'var(--ggui-spacing-4, 16px)' : 'var(--ggui-spacing-1, 4px)',
            animation: motionEnabled ? (animation.fadeIn + ' 0.2s ease-out') : 'none',
          }}
        >
          {isFirst && !isOwn && (
            <Text variant="label" weight="semibold" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {msg.sender ?? 'Unknown'}
            </Text>
          )}
          <div style={{
            maxWidth: '75%',
            padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
            borderRadius: bubbleRadius,
            background: isOwn ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            color: isOwn ? ownText : 'var(--ggui-color-onSurface, #18181b)',
            wordBreak: 'break-word',
          }}>
            <Text variant="body" color={isOwn ? ownText : 'var(--ggui-color-onSurface, #18181b)'}>
              {msg.text ?? ''}
            </Text>
          </div>
          {isLast && (
            <Text
              variant="caption"
              color={isOwn ? ownTimestamp : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
              align={isOwn ? 'right' : 'left'}
            >
              {formatTimestamp(msg.timestamp)}
            </Text>
          )}
        </div>
      );
    });

  return (
    <Container maxWidth="md">
      <MotionKeyframes />
      <Card padding={0} shadow="md" border>
        <Stack direction="vertical" gap={0}>

          {/* HEADER */}
          <div style={{
            padding: 'var(--ggui-spacing-4, 16px) var(--ggui-spacing-6, 24px)',
            background: 'var(--ggui-color-primary-50, #f0f9ff)',
            borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
          }}>
            <Row align="center" justify="between">
              <Text variant="h3" weight="bold" color="var(--ggui-color-primary-900, #0c4a6e)">
                {title}
              </Text>
              {participantCount != null && (
                <Badge
                  variant="primary"
                  size="sm"
                  pill
                  aria-label={String(participantCount) + (participantCount === 1 ? ' participant' : ' participants')}
                >
                  <span style={{ display: 'inline-flex', alignItems: 'center', gap: 'var(--ggui-spacing-1, 4px)' }}>
                    <Icon name="users" size={12} color="currentColor" />
                    {' '}{participantCount}{' '}{participantCount === 1 ? 'participant' : 'participants'}
                  </span>
                </Badge>
              )}
            </Row>
          </div>

          {/* MESSAGE LIST */}
          <div
            role="log"
            aria-live="polite"
            aria-label="Chat messages"
            style={{
              height: 400,
              overflowY: 'auto',
              padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-6, 24px) var(--ggui-spacing-4, 16px)',
              background: 'var(--ggui-color-surface, #fafafa)',
            }}
          >
            {allMessages.length === 0 && (
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%' }}>
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                  No messages yet. Start the conversation!
                </Text>
              </div>
            )}
            {renderMessages()}
            <div ref={messagesEndRef} aria-hidden="true" />
          </div>

          {/* INPUT AREA */}
          <div
            style={{
              padding: 'var(--ggui-spacing-4, 16px) var(--ggui-spacing-6, 24px)',
              borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)',
              background: 'var(--ggui-color-surface, #fafafa)',
            }}
            onKeyDown={handleKeyDown}
          >
            <Row align="center" gap={8}>
              <div style={{ flex: 1 }}>
                <Text as="label" htmlFor={inputId} variant="srOnly">Type a message</Text>
                <Input id={inputId} label="Type a message" placeholder="Type a message..." value={inputValue} onChange={setInputValue} />
              </div>
              <Button
                variant="primary"
                onClick={handleSend}
                disabled={isSendDisabled}
                aria-label="Send message"
                rightIcon={
                  <Icon size={16} color="currentColor" viewBox="0 0 24 24">
                    <path d="M2.01 21L23 12 2.01 3 2 10l15 2-15 2z" fill="currentColor" />
                  </Icon>
                }
              >
                Send
              </Button>
            </Row>
          </div>

        </Stack>
      </Card>
    </Container>
  );
}

