  { symbol: 'TSLA', name: 'Tesla Inc.', price: 248.42, change: 7.86, changePercent: 3.27 },
  { symbol: 'NVDA', name: 'NVIDIA Corp.', price: 875.28, change: 12.54, changePercent: 1.45 },
];

export default function GeneratedComponent(props: Props) {
  const {
    stocks: propStocks,
    lastUpdated: propLastUpdated,
  } = props;

  const initialStocks = propStocks ?? DEFAULT_STOCKS;
  const initialLastUpdated = propLastUpdated ?? new Date().toISOString();

  // --- STATE ---
  const [stocks, setStocks] = useState<StockItem[]>(initialStocks);
  const [lastUpdated, setLastUpdated] = useState<string>(initialLastUpdated);
  const [connectionStatus, setConnectionStatus] = useState<
    'connecting' | 'connected' | 'disconnected'
  >('connecting');
  const { motionEnabled } = useMotion();

  // --- STREAM CONTRACT: useAgentData hook handles ggui:agent-data events safely ---
  useAgentData((data) => {
    if (data && data.stocks) {
      setStocks(data.stocks);
    }
    if (data && data.lastUpdated) {
      setLastUpdated(data.lastUpdated);
    }
    setConnectionStatus('connected');
  });

  // Simulate connection handshake on mount
  useEffect(() => {
    const connectTimer = setTimeout(() => {
      setConnectionStatus('connected');
    }, 800);
    return () => clearTimeout(connectTimer);
  }, []);

  // Sync with prop changes
  useEffect(() => {
    if (propStocks) setStocks(propStocks);
  }, [propStocks]);

  useEffect(() => {
    if (propLastUpdated) setLastUpdated(propLastUpdated);
  }, [propLastUpdated]);

  // --- HELPERS ---
  const formatTimestamp = (iso: string): string => {
    try {
      const date = new Date(iso);
      return date.toLocaleTimeString(undefined, {
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
      });
    } catch {
      return iso;
    }
  };

  const isPositive = (val?: number): boolean => val != null && val >= 0;

  const statusBadgeVariant =
    connectionStatus === 'connected'
      ? 'success'
      : connectionStatus === 'connecting'
      ? 'warning'
      : 'error';

  const statusLabel =
    connectionStatus === 'connected'
      ? 'Live'
      : connectionStatus === 'connecting'
      ? 'Connecting…'
      : 'Disconnected';

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
        <Stack direction="vertical" gap={24}>

          {/* === HEADER === */}
          <Box
            padding="var(--ggui-spacing-4, 16px) var(--ggui-spacing-6, 24px)"
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            borderRadius="var(--ggui-shape-radius-lg, 12px)"
          >
            <Row align="center" justify="between" wrap>
              <Row align="center" gap={12}>
                <Text variant="h2" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                  Market Watch
                </Text>
                <Badge variant={statusBadgeVariant} size="sm" pill>
                  {statusLabel}
                </Badge>
              </Row>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Last Updated: {formatTimestamp(lastUpdated)}
              </Text>
            </Row>
          </Box>

          {/* === LOADING / CONNECTING STATE === */}
          {connectionStatus === 'connecting' && stocks.length === 0 && (
            <Box
              padding="var(--ggui-spacing-12, 48px)"
              borderRadius="var(--ggui-shape-radius-md, 8px)"
            >
              <Stack align="center" gap={12}>
                <Text
                  variant="body"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  align="center"
                >
                  Connecting to market data…
                </Text>
              </Stack>
            </Box>
          )}

          {/* === STOCK CARDS GRID === */}
          {stocks.length > 0 && (
            <div
              role="list"
              aria-label="Stock prices"
              aria-live="polite"
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
                gap: 'var(--ggui-spacing-4, 16px)',
              }}
            >
              {stocks.map((stock, index) => {
                const positive = isPositive(stock.change);
                const changeColor = positive
                  ? 'var(--ggui-color-success-600, #16a34a)'
                  : 'var(--ggui-color-error-600, #dc2626)';
                const borderColor = positive
                  ? 'var(--ggui-color-success-500, #22c55e)'
                  : 'var(--ggui-color-error-500, #ef4444)';
                const arrow = positive ? '▲' : '▼';
                const sign = positive ? '+' : '';

                const symbolLabel = stock.symbol ?? 'Stock';
                const priceLabel = stock.price != null ? stock.price.toFixed(2) : 'N/A';
                const cardAriaLabel = symbolLabel + ': ' + priceLabel;

                const changePercentDisplay =
                  stock.changePercent != null
                    ? sign + stock.changePercent.toFixed(2) + '%'
                    : '—';

                const changeDisplay =
                  stock.change != null
                    ? sign + stock.change.toFixed(2)
                    : '—';

                const priceDisplay =
                  stock.price != null ? '$' + stock.price.toFixed(2) : '—';

                return (
                  <div
                    key={stock.symbol ?? index}
                    role="listitem"
                    aria-label={cardAriaLabel}
                    style={{
                      animation: motionEnabled ? animation.fadeIn : 'none',
                      animationDelay: motionEnabled ? index * 60 + 'ms' : '0ms',
                    }}
                  >
                    <Card padding={0} shadow="sm" border>
                      <div
                        style={{
                          borderLeft: '4px solid ' + borderColor,
                          borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                          padding: 'var(--ggui-spacing-4, 16px)',
                          transition: transition.colors,
                        }}
                      >
                        <Stack direction="vertical" gap={8}>
                          {/* Top row: Symbol + Change badge */}
                          <Row align="center" justify="between">
                            <Text
                              variant="h3"
                              weight="bold"
                              color="var(--ggui-color-onSurface, #18181b)"
                            >
                              {stock.symbol ?? '—'}
                            </Text>
                            <Badge
                              variant={positive ? 'success' : 'error'}
                              size="sm"
                              pill
                            >
                              {arrow} {changePercentDisplay}
                            </Badge>
                          </Row>

                          {/* Company name */}
                          <Text
                            variant="caption"
                            color="var(--ggui-color-onSurfaceVariant, #52525b)"
                          >
                            {stock.name ?? 'Unknown Company'}
                          </Text>

                          {/* Price + Change row */}
                          <Row align="end" justify="between">
                            <Text
                              variant="h2"
                              weight="bold"
                              color="var(--ggui-color-onSurface, #18181b)"
                            >
                              {priceDisplay}
                            </Text>
                            <Text
                              variant="body"
                              weight="semibold"
                              color={changeColor}
                            >
                              {changeDisplay}
                            </Text>
                          </Row>
                        </Stack>
                      </div>
                    </Card>
                  </div>
                );
              })}
            </div>
          )}

          {/* === EMPTY STATE === */}
          {stocks.length === 0 && connectionStatus === 'connected' && (
            <Box
              padding="var(--ggui-spacing-12, 48px)"
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
              borderRadius="var(--ggui-shape-radius-lg, 12px)"
            >
              <Text
                variant="body"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
                align="center"
              >
                No stock data available. Waiting for market data…
              </Text>
            </Box>
          )}

        </Stack>
      </Container>
    </>
  );
}

import { useState, useMemo } from 'react';
import {
  Container, Card, Stack, Row, Text, Input, Select, Checkbox,
  RadioGroup, Button, Divider, Badge, Icon, Box, MotionKeyframes, useMotion
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface ProfileData {
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: string;
}

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string };
  onComplete?: (data: ProfileData) => void;
}

const STEP_LABELS = ['Profile Setup', 'Preferences', 'Review & Confirm'];
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export default function GeneratedComponent({ initialProfile, avatarOptions, roleOptions, onComplete }: Props) {
  const { motionEnabled } = useMotion();

  const [currentStep, setCurrentStep] = useState(0);
  const [name, setName] = useState(initialProfile?.name ?? '');
  const [email, setEmail] = useState(initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState(initialProfile?.avatar ?? '');
  const [role, setRole] = useState(initialProfile?.role ?? (roleOptions[0] ?? ''));
  const [emailNotifications, setEmailNotifications] = useState(initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState(initialProfile?.theme ?? 'light');
  const [touched, setTouched] = useState<Record<string, boolean>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);

  const nameError = touched.name && !name.trim() ? 'Name is required' : '';
  const emailError = touched.email
    ? !email.trim() ? 'Email is required' : !EMAIL_REGEX.test(email) ? 'Please enter a valid email' : ''
    : '';

  const step1Valid = name.trim() !== '' && EMAIL_REGEX.test(email) && avatar !== '';
  const step2Valid = role !== '';

  const isNextDisabled = useMemo(() => {
    if (currentStep === 0) return !step1Valid;
    if (currentStep === 1) return !step2Valid;
    return false;
  }, [currentStep, step1Valid, step2Valid]);

  const progressPercent = (currentStep / 2) * 100;
  const stepLabels = ['1 of 3', '2 of 3', '3 of 3'] as const;
  const nextStepLabels = ['step 2 of 3', 'step 3 of 3'] as const;
  const progressAriaLabel = ['Step 1 of 3', 'Step 2 of 3', 'Step 3 of 3'][currentStep];

  const handleNameChange = (value: string) => {
    setName(value);
    if (!touched.name) setTouched(p => ({ ...p, name: true }));
  };

  const handleEmailChange = (value: string) => {
    setEmail(value);
    if (!touched.email) setTouched(p => ({ ...p, email: true }));
  };

  const handleNext = () => {
    if (currentStep === 0) {
      setTouched(p => ({ ...p, name: true, email: true }));
      if (!step1Valid) return;
    }
    if (currentStep === 1 && !step2Valid) return;
    if (currentStep < 2) setCurrentStep(p => p + 1);
  };

  const handleBack = () => { if (currentStep > 0) setCurrentStep(p => p - 1); };
  const handleGoBackToEdit = () => setCurrentStep(0);

  const handleComplete = async () => {
    setIsSubmitting(true);
    try {
      onComplete?.({ name: name.trim(), email: email.trim(), avatar, role, emailNotifications, theme });
    } finally {
      setIsSubmitting(false);
    }
  };

  const roleSelectOptions = roleOptions.map(r => ({ value: r, label: r }));

  const themeCapitalized = theme === 'light' ? 'Light' : 'Dark';
  const avatarReviewLabel = 'Selected avatar: ' + avatar;

  const renderStepIndicator = () => (
    <Stack gap={0} align="center">
      <div
        role="progressbar"
        aria-valuenow={progressPercent}
        aria-valuemin={0}
        aria-valuemax={100}
        aria-label={progressAriaLabel}
        style={{
          width: '100%', maxWidth: 300, height: 4,
          background: 'var(--ggui-color-outlineVariant, #e4e4e7)',
          borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
          overflow: 'hidden',
          marginBottom: 'var(--ggui-spacing-4, 16px)',
        }}
      >
        <div style={{
          width: progressPercent === 0 ? '0%' : progressPercent === 50 ? '50%' : '100%',
          height: '100%',
          background: 'var(--ggui-color-primary-600, #0284c7)',
          borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
          transition: motionEnabled ? 'width 350ms cubic-bezier(0.4,0,0.2,1)' : 'none',
        }} />
      </div>

      <Row gap={32} justify="center" align="start">
        {STEP_LABELS.map((label, i) => {
          const isCompleted = i < currentStep;
          const isActive = i === currentStep;
          const isClickable = i <= currentStep;
          const stepAriaLabel = 'Step ' + stepLabels[i] + ': ' + label;
          return (
            <Stack key={label} gap={6} align="center">
              <div
                role="button"
                tabIndex={isClickable ? 0 : -1}
                aria-label={stepAriaLabel}
                aria-current={isActive ? 'step' : undefined}
                onClick={() => { if (isClickable) setCurrentStep(i); }}
                onKeyDown={(e) => { if (isClickable && (e.key === 'Enter' || e.key === ' ')) { e.preventDefault(); setCurrentStep(i); } }}
                style={{
                  width: 36, height: 36,
                  borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  fontWeight: 600,
                  fontSize: 'var(--ggui-font-size-sm, 14px)',
                  cursor: isClickable ? 'pointer' : 'default',
                  transition: motionEnabled ? 'background 200ms ease, border-color 200ms ease' : 'none',
                  background: isCompleted ? 'var(--ggui-color-success-600, #16a34a)' : isActive ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  color: isCompleted || isActive ? 'var(--ggui-color-onPrimary, #ffffff)' : 'var(--ggui-color-onSurfaceVariant, #52525b)',
                  border: isActive ? '2px solid var(--ggui-color-primary-600, #0284c7)' : isCompleted ? '2px solid var(--ggui-color-success-600, #16a34a)' : '2px solid var(--ggui-color-outline, #d4d4d8)',
                  outline: 'none', userSelect: 'none',
                }}
              >
                {isCompleted ? <Icon name="check" size={16} /> : <span>{i + 1}</span>}
              </div>
              <Text variant="caption" align="center" weight={isActive ? 'semibold' : 'normal'}
                color={isActive ? 'var(--ggui-color-onSurface, #18181b)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}>
                {label}
              </Text>
            </Stack>
          );
        })}
      </Row>
    </Stack>
  );

  const renderStep1 = () => (
    <Stack gap={20}>
      <Stack gap={4}>
        <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">Profile Setup</Text>
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Tell us about yourself to get started.</Text>
      </Stack>

      <Input label="Name" placeholder="Enter your full name" value={name} onChange={handleNameChange} required error={nameError} />

      <Input label="Email" type="email" placeholder="you@example.com" value={email} onChange={handleEmailChange} required error={emailError} />

      <Stack gap={8}>
        <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
          Choose an Avatar <span aria-hidden="true" style={{ color: 'var(--ggui-color-error-500, #ef4444)' }}>*</span>
        </Text>
        <Row gap={12} wrap role="radiogroup" aria-label="Choose avatar">
          {avatarOptions.map((emoji) => {
            const isSelected = avatar === emoji;
            const emojiLabel = 'Avatar option ' + emoji;
            return (
              <div
                key={emoji}
                role="radio"
                aria-checked={isSelected}
                aria-label={emojiLabel}
                tabIndex={0}
                onClick={() => setAvatar(emoji)}
                onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); setAvatar(emoji); } }}
                style={{
                  width: 56, height: 56,
                  borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  fontSize: 28, cursor: 'pointer',
                  transition: motionEnabled ? 'background 180ms ease, border-color 180ms ease, box-shadow 180ms ease' : 'none',
                  background: isSelected ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  border: isSelected ? '2px solid var(--ggui-color-primary-600, #0284c7)' : '2px solid var(--ggui-color-outline, #d4d4d8)',
                  boxShadow: isSelected ? '0 0 0 3px var(--ggui-color-primary-100, #e0f2fe)' : 'none',
                  outline: 'none', userSelect: 'none',
                }}
              >
                {emoji}
              </div>
            );
          })}
        </Row>
        {!avatar && touched.name && (
          <Text variant="caption" color="var(--ggui-color-error-500, #ef4444)">Please select an avatar</Text>
        )}
      </Stack>
    </Stack>
  );

  const renderStep2 = () => (
    <Stack gap={20}>
      <Stack gap={4}>
        <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">Preferences</Text>
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Customize your experience.</Text>
      </Stack>
      <Select label="Role" value={role} onChange={setRole} options={roleSelectOptions} placeholder="Select your role" required />
      <Checkbox label="Email Notifications" checked={emailNotifications} onChange={setEmailNotifications} description="Receive email updates about activity and announcements" />
      <RadioGroup
        label="Theme Preference"
        value={theme}
        onChange={setTheme}
        options={[
          { value: 'light', label: 'Light', description: 'Clean and bright interface' },
          { value: 'dark', label: 'Dark', description: 'Easy on the eyes in low light' },
        ]}
        direction="horizontal"
      />
    </Stack>
  );

  const renderStep3 = () => (
    <Stack gap={20}>
      <Stack gap={4}>
        <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">Review & Confirm</Text>
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Please review your information before completing setup.</Text>
      </Stack>
      <Box
        background="var(--ggui-color-surfaceVariant, #f4f4f5)"
        borderRadius="var(--ggui-shape-radius-lg, 12px)"
        padding="var(--ggui-spacing-6, 24px)"
      >
        <Stack gap={14}>
          <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)">PROFILE</Text>
          <Row justify="between" align="center">
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name</Text>
            <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{name}</Text>
          </Row>
          <Row justify="between" align="center">
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email</Text>
            <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{email}</Text>
          </Row>
          <Row justify="between" align="center">
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Avatar</Text>
            <span role="img" aria-label={avatarReviewLabel} style={{ fontSize: 28, lineHeight: 1 }}>{avatar}</span>
          </Row>
          <Divider />
          <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)">PREFERENCES</Text>
          <Row justify="between" align="center">
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Role</Text>
            <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{role}</Text>
          </Row>
          <Row justify="between" align="center">
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email Notifications</Text>
            <Badge variant={emailNotifications ? 'success' : 'default'} size="sm">{emailNotifications ? 'Enabled' : 'Disabled'}</Badge>
          </Row>
          <Row justify="between" align="center">
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Theme</Text>
            <Badge variant="primary" size="sm">{themeCapitalized}</Badge>
          </Row>
        </Stack>
      </Box>
    </Stack>
  );

  const nextAriaLabel = currentStep === 0 ? 'Proceed to step 2 of 3' : nextStepLabels[currentStep] ? 'Proceed to ' + nextStepLabels[currentStep] : 'Next';

  const renderNavigation = () => (
    <Row justify="between" align="center">
      {currentStep === 0 ? (
        <span aria-hidden="true" />
      ) : currentStep === 2 ? (
        <Button variant="outline" onClick={handleGoBackToEdit} leftIcon={<Icon name="chevron-left" size={16} />} aria-label="Go back to edit profile">
          Go Back
        </Button>
      ) : (
        <Button variant="outline" onClick={handleBack} leftIcon={<Icon name="chevron-left" size={16} />} aria-label="Go to previous step">
          Back
        </Button>
      )}
      {currentStep < 2 ? (
        <Button variant="primary" onClick={handleNext} disabled={isNextDisabled} rightIcon={<Icon name="chevron-right" size={16} />} aria-label={nextAriaLabel}>
          Next
        </Button>
      ) : (
        <Button variant="primary" onClick={handleComplete} loading={isSubmitting} disabled={isSubmitting} leftIcon={<Icon name="check" size={16} />} aria-label="Complete setup and submit">
          {isSubmitting ? 'Completing\u2026' : 'Complete Setup'}
        </Button>
      )}
    </Row>
  );

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="sm" padding="var(--ggui-spacing-8, 32px)">
        <Card padding={32} shadow="md">
          <Stack gap={24}>
            <Text variant="h2" align="center" color="var(--ggui-color-onSurface, #18181b)">
              Welcome! Let&apos;s get started
            </Text>
            {renderStepIndicator()}
            <Divider />
            <div key={currentStep} style={{ animation: motionEnabled ? animation.fadeIn : 'none' }}>
              {currentStep === 0 && renderStep1()}
              {currentStep === 1 && renderStep2()}
              {currentStep === 2 && renderStep3()}
            </div>
            <Divider />
            {renderNavigation()}
          </Stack>
        </Card>
      </Container>
    </>
  );
}

import React from 'react';
import { Card, Stack, Row, Text, Divider } from '@ggui-ai/design/primitives';

interface ForecastItem {
  day?: string;
  icon?: string;
  high?: number;
  low?: number;
}

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: ForecastItem[];
}

/**
 * WeatherCard Component
 * Displays current weather conditions and a 5-day forecast.
 */
export default function WeatherCard({
  city = 'San Francisco',
  temperature = 72,
  condition = 'Sunny',
  humidity = 45,
  windSpeed = 12,
  unit = '°F',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 75, low: 60 },
    { day: 'Tue', icon: '⛅', high: 72, low: 58 },
    { day: 'Wed', icon: '☁️', high: 68, low: 55 },
    { day: 'Thu', icon: '🌧️', high: 62, low: 50 },
    { day: 'Fri', icon: '☀️', high: 70, low: 58 },
  ],
}: Props) {
  /**
   * Utility to map common condition strings to emojis
   */
  const getWeatherEmoji = (cond: string): string => {
    const c = cond.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain') || c.includes('drizzle')) return '🌧️';
    if (c.includes('storm') || c.includes('thunder')) return '⛈️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('fog') || c.includes('mist')) return '🌫️';
    return '🌡️';
  };

  return (
    <Card 
      padding="var(--ggui-spacing-6, 24px)" 
      shadow="md"
      style={{
        backgroundColor: 'var(--ggui-color-surface, #ffffff)',
        borderColor: 'var(--ggui-color-outline, #e4e4e7)',
        maxWidth: '450px',
