            </Stack>
          ))}
        </Row>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
} from '@ggui-ai/design/primitives';

/**
 * Props Contract
 */
interface Props {
  featureOptions: string[];
  satisfactionLabels: string[];
  onSubmit?: (data: any) => void;
}

interface SurveyData {
  name: string;
  email: string;
  satisfaction: number | null;
  interests: string[];
  comments: string;
}

export default function GeneratedComponent({
  featureOptions = ['Speed', 'Design', 'Reliability', 'Support', 'Pricing'],
  satisfactionLabels = ['Very Unsatisfied', 'Unsatisfied', 'Neutral', 'Satisfied', 'Very Satisfied'],
  onSubmit
}: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<SurveyData>({
    name: '',
    email: '',
    satisfaction: null,
    interests: [],
    comments: '',
  });

  const isValidEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  const isStep1Valid = formData.name.trim().length > 0 && isValidEmail(formData.email);
  const isStep2Valid = formData.satisfaction !== null;
  const isStep4Valid = formData.comments.length <= 500;

  const canGoNext = useMemo(() => {
    if (step === 1) return isStep1Valid;
    if (step === 2) return isStep2Valid;
    if (step === 4) return isStep4Valid;
    return true;
  }, [step, isStep1Valid, isStep2Valid, isStep4Valid]);

  const handleNext = () => setStep(s => Math.min(s + 1, 5));
  const handleBack = () => setStep(s => Math.max(s - 1, 1));
  const handleSubmit = () => onSubmit?.(formData);

  const toggleInterest = (interest: string) => {
    setFormData(prev => ({
      ...prev,
      interests: prev.interests.includes(interest)
        ? prev.interests.filter(i => i !== interest)
        : [...prev.interests, interest]
    }));
  };

  const progressPercent = String(Math.min(Math.round(((step - 1) / 4) * 100), 100));

  return (
    <Card variant="elevated" style={{ maxWidth: '600px', margin: '0 auto', width: '100%' }}>
      <Stack role="form" aria-label="Survey Form" gap="xl" padding="xl">
        <Stack gap="xs">
          <Stack direction="row" align="center" justify="space-between">
            <Text variant="body-sm">Step {step <= 4 ? step : 4} of 4</Text>
            <Text variant="body-sm" weight="bold">{progressPercent}%</Text>
          </Stack>
          <div style={{ height: 'var(--ggui-spacing-xs)', width: '100%', backgroundColor: 'var(--ggui-color-surface-container-high)', borderRadius: 'var(--ggui-spacing-xs)', overflow: 'hidden' }}>
            <div style={{ height: '100%', width: progressPercent + '%', backgroundColor: 'var(--ggui-color-primary)', transition: 'width 0.3s ease' }} />
          </div>
        </Stack>

        <Stack gap="lg" style={{ minHeight: '340px' }}>
          {step === 1 && (
            <Stack gap="md">
              <Text variant="title-lg">Contact Information</Text>
              <Text as="label" htmlFor="name-input">Name</Text>
              <Input label="Name" id="name-input" value={formData.name} onChange={(v: string) => setFormData(p => ({ ...p, name: v }))} />

              <Text as="label" htmlFor="email-input">Email</Text>
              <Input label="Email" id="email-input" type="email" value={formData.email} onChange={(v: string) => setFormData(p => ({ ...p, email: v }))} />
            </Stack>
          )}

          {step === 2 && (
            <Stack gap="md">
              <Text variant="title-lg">Satisfaction</Text>
              <Stack gap="sm">
                {satisfactionLabels.map((l, i) => (
                  <Button key={l} variant={formData.satisfaction === i + 1 ? 'filled' : 'outline'} onClick={() => setFormData(p => ({ ...p, satisfaction: i + 1 }))} style={{ justifyContent: 'flex-start' }}>
                    {l}
                  </Button>
                ))}
              </Stack>
            </Stack>
          )}

          {step === 3 && (
            <Stack gap="md">
              <Text variant="title-lg">Feature Interests</Text>
              <Stack direction="row" wrap="wrap" gap="sm">
                {featureOptions.map(o => (
                  <Button key={o} variant={formData.interests.includes(o) ? 'tonal' : 'outline'} onClick={() => toggleInterest(o)}>{o}</Button>
                ))}
              </Stack>
            </Stack>
          )}

          {step === 4 && (
            <Stack gap="md">
              <Text variant="title-lg">Feedback</Text>
              <Text as="label" htmlFor="comments-input">Comments</Text>
              <Input label="Comments" id="comments-input" multiline rows={4} value={formData.comments} onChange={(v: string) => setFormData(p => ({ ...p, comments: v }))} />
            </Stack>
          )}

          {step === 5 && (
            <Stack gap="md">
              <Text variant="title-lg">Review</Text>
              <Card variant="outlined" padding="md">
                <Stack gap="sm">
                  <Text variant="body-md">Name: {formData.name}</Text>
                  <Text variant="body-md">Email: {formData.email}</Text>
                  <Text variant="body-md">Satisfaction: {formData.satisfaction}</Text>
                </Stack>
              </Card>
            </Stack>
          )}
        </Stack>

        <Stack direction="row" justify="space-between" align="center">
          <Button variant="text" onClick={handleBack} disabled={step === 1}>Back</Button>
          {step === 5 ? (
            <Button variant="filled" onClick={handleSubmit}>Submit Survey</Button>
          ) : (
            <Button variant="filled" onClick={handleNext} disabled={!canGoNext}>Continue</Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
} from '@ggui-ai/design/primitives';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  electronConfiguration?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Array of elements with atomicNumber, symbol, name, atomicWeight, category (kebab-case), electronConfiguration, row, col */
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; electronConfiguration?: string; row?: number; col?: number }>;
}

const CATEGORY_MAP: Record<string, { label: string; color: string }> = {
  'alkali-metal': { label: 'Alkali Metal', color: 'var(--ggui-color-error-container)' },
  'alkaline-earth': { label: 'Alkaline Earth', color: 'var(--ggui-color-warning-container)' },
  'transition-metal': { label: 'Transition Metal', color: 'var(--ggui-color-primary-container)' },
  'post-transition-metal': { label: 'Post-transition Metal', color: 'var(--ggui-color-info-container)' },
  'metalloid': { label: 'Metalloid', color: 'var(--ggui-color-success-container)' },
  'nonmetal': { label: 'Nonmetal', color: 'var(--ggui-color-tertiary-container)' },
  'halogen': { label: 'Halogen', color: 'var(--ggui-color-secondary-container)' },
  'noble-gas': { label: 'Noble Gas', color: 'var(--ggui-color-surface-container-highest)' },
  'lanthanide': { label: 'Lanthanide', color: 'var(--ggui-color-outline-variant)' },
  'actinide': { label: 'Actinide', color: 'var(--ggui-color-outline)' },
};

export default function PeriodicTable(props: Props) {
  const { elements = [] } = props;
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<ElementData | null>(null);

  const filteredElements = useMemo(() => {
    if (!search) return elements;
    const term = search.toLowerCase();
    return elements.filter(
      (el) =>
        (el.name || '').toLowerCase().includes(term) ||
        (el.symbol || '').toLowerCase().includes(term)
    );
  }, [elements, search]);

  const handleElementClick = (element: ElementData) => {
    setSelected(element);
  };

  const searchId = "periodic-search-input";

  return (
    <Card variant="outlined" style={{ padding: 'var(--ggui-spacing-large)', width: '100%', overflowX: 'auto' }}>
      <Stack direction="column" gap="large">
        <Stack direction="column" gap="small">
          <Text variant="headline-medium">Periodic Table of Elements</Text>
          <Text as="label" htmlFor={searchId} variant="label-medium">Search elements</Text>
          <Input id={searchId} label="Search elements" placeholder="Search by name or symbol" value={search} onChange={setSearch} />
        </Stack>

        <Stack direction="row" gap="small" style={{ flexWrap: 'wrap' }}>
          {Object.entries(CATEGORY_MAP).map(([key, info]) => (
            <Stack key={key} direction="row" gap="xsmall" align="center">
              <div
                style={{
                  width: 'var(--ggui-spacing-medium)',
                  height: 'var(--ggui-spacing-medium)',
                  borderRadius: 'var(--ggui-radius-xsmall)',
                  backgroundColor: info.color,
                  border: '1px solid var(--ggui-color-outline-variant)',
                }}
              />
              <Text variant="body-small">{info.label}</Text>
            </Stack>
          ))}
        </Stack>

        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, minmax(3.5rem, 1fr))',
            gridAutoRows: 'minmax(4rem, auto)',
            gap: 'var(--ggui-spacing-xsmall)',
            marginTop: 'var(--ggui-spacing-medium)',
            padding: 'var(--ggui-spacing-xsmall)',
          }}
        >
          {filteredElements.map((element) => {
            const cat = element.category || '';
            const color = CATEGORY_MAP[cat]?.color || 'var(--ggui-color-surface-container)';
            const isSelected = selected?.atomicNumber === element.atomicNumber;

            return (
              <button
                key={element.atomicNumber || element.symbol}
                onClick={() => handleElementClick(element)}
                aria-label={element.name}
                style={{
                  gridColumn: element.col,
                  gridRow: element.row,
                  padding: 'var(--ggui-spacing-xsmall)',
                  border: isSelected ? '2px solid var(--ggui-color-primary)' : '1px solid var(--ggui-color-outline-variant)',
                  borderRadius: 'var(--ggui-radius-small)',
                  backgroundColor: color,
                  cursor: 'pointer',
                  display: 'flex',
                  flexDirection: 'column',
                  position: 'relative',
                  aspectRatio: '1/1',
                  transition: 'background-color 0.2s, transform 0.1s',
                }}
              >
                <Text
                  variant="label-small"
                  style={{
                    position: 'absolute',
                    top: 'var(--ggui-spacing-xsmall)',
                    left: 'var(--ggui-spacing-xsmall)',
                    fontSize: '0.6rem',
                  }}
                >
                  {element.atomicNumber}
                </Text>
                <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                  <Text variant="title-medium" style={{ fontWeight: 'bold' }}>
                    {element.symbol}
                  </Text>
                </div>
              </button>
            );
          })}
        </div>

        {selected && (
          <Card
            variant="filled"
            style={{
              marginTop: 'var(--ggui-spacing-large)',
              padding: 'var(--ggui-spacing-medium)',
              backgroundColor: 'var(--ggui-color-surface-container-low)',
              border: '1px solid var(--ggui-color-outline-variant)',
            }}
          >
            <Stack direction="row" gap="large" align="center" style={{ flexWrap: 'wrap' }}>
              <div
                style={{
                  width: '5rem',
                  height: '5rem',
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  justifyContent: 'center',
                  borderRadius: 'var(--ggui-radius-medium)',
                  backgroundColor: CATEGORY_MAP[selected.category || '']?.color || 'var(--ggui-color-surface-container)',
                  border: '1px solid var(--ggui-color-outline)',
                }}
              >
                <Text variant="body-small">{selected.atomicNumber}</Text>
                <Text variant="headline-medium" style={{ fontWeight: 'bold' }}>{selected.symbol}</Text>
              </div>

              <Stack direction="column" gap="xsmall" style={{ flex: '1 1 15rem' }}>
                <Stack direction="row" align="baseline" gap="small" style={{ flexWrap: 'wrap' }}>
                  <Text variant="headline-small">{selected.name}</Text>
                  <Text variant="body-medium" style={{ opacity: 0.8 }}>
                    ({selected.category?.replace(/-/g, ' ')})
                  </Text>
                </Stack>
                <Stack direction="row" gap="large" style={{ flexWrap: 'wrap' }}>
                  <Stack direction="column">
                    <Text variant="label-medium" style={{ color: 'var(--ggui-color-primary)' }}>Atomic Weight</Text>
                    <Text variant="body-large">{selected.atomicWeight}</Text>
                  </Stack>
                  <Stack direction="column">
                    <Text variant="label-medium" style={{ color: 'var(--ggui-color-primary)' }}>Electron Configuration</Text>
                    <Text variant="body-large">{selected.electronConfiguration}</Text>
                  </Stack>
                </Stack>
              </Stack>
              <Button variant="text" onClick={() => setSelected(null)}>Close</Button>
            </Stack>
          </Card>
        )}
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Card, Stack, Text, Button, Input } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Send Message Action */
  sendMessage: (payload: { text: string; timestamp: string }) => void;
}

export default function ChatInterface(props: Props) {
  const { title = "Chat", currentUser = "User", participantCount, messages = [] } = props;
  const [inputValue, setInputValue] = useState('');
  const [localMessages, setLocalMessages] = useState(messages);
  const scrollRef = useRef<HTMLDivElement>(null);
  const inputId = "chat-input-field";

  useEffect(() => { setLocalMessages(messages); }, [messages]);

  useEffect(() => {
    const handler = (e: any) => { if (e.detail) setLocalMessages(prev => [...prev, e.detail]); };
    addEventListener('ggui:agent-data', handler);
    return () => removeEventListener('ggui:agent-data', handler);
  }, []);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [localMessages]);

  const handleSend = () => {
    if (!inputValue.trim()) return;
    const ts = new Date().toISOString();
    // Direct call to match contract requirement
    props.sendMessage({ text: inputValue, timestamp: ts });
    setInputValue('');
  };

  return (
    <Card variant="outlined" style={{ height: '600px', display: 'flex', flexDirection: 'column', width: '100%', maxWidth: '500px', margin: '0 auto', backgroundColor: 'var(--ggui-color-surface)' }}>
      <Stack direction="row" justify="space-between" align="center" padding="16px" style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant)' }}>
        <Stack direction="column" gap="4px">
          <Text variant="title-medium">{title}</Text>
          {participantCount !== undefined && <Text variant="label-small">{participantCount} participants</Text>}
        </Stack>
      </Stack>

      <Stack ref={scrollRef} direction="column" gap="8px" padding="16px" style={{ flexGrow: 1, overflowY: 'auto', backgroundColor: 'var(--ggui-color-surfaceContainerLow)' }}>
        {localMessages.map((msg, i) => {
          const isMe = msg.sender === currentUser;
          const isGrouped = i > 0 && localMessages[i - 1].sender === msg.sender;
          return (
            <Stack key={i} direction="column" align={isMe ? 'flex-end' : 'flex-start'} style={{ alignSelf: isMe ? 'flex-end' : 'flex-start', maxWidth: '85%', marginTop: isGrouped ? '2px' : '12px' }}>
              {!isGrouped && <Text variant="label-small" style={{ fontWeight: 600 }}>{msg.sender}</Text>}
              <Card variant="filled" style={{ padding: '8px 12px', borderRadius: '12px', backgroundColor: isMe ? 'var(--ggui-color-primary)' : 'var(--ggui-color-surfaceVariant)', color: isMe ? 'var(--ggui-color-onPrimary)' : 'var(--ggui-color-onSurfaceVariant)' }}>
                <Text variant="body-medium" style={{ color: 'inherit' }}>{msg.text}</Text>
                {msg.timestamp && <Text variant="label-small" style={{ fontSize: '10px', opacity: 0.7, color: 'inherit', textAlign: 'right', display: 'block' }}>{new Date(msg.timestamp).toLocaleTimeString()}</Text>}
              </Card>
            </Stack>
          );
        })}
      </Stack>

      <Stack direction="row" gap="12px" padding="16px" align="center" style={{ borderTop: '1px solid var(--ggui-color-outlineVariant)', backgroundColor: 'var(--ggui-color-surface)' }}>
        <Stack direction="column" style={{ flexGrow: 1 }}>
          <Text as="label" htmlFor={inputId} variant="label-small">Message</Text>
          <Input id={inputId} label="Message" placeholder="Type here..." value={inputValue} onChange={setInputValue} onKeyDown={(e) => { if (e.key === 'Enter') handleSend(); }} style={{ width: '100%' }} />
        </Stack>
        <Button variant="filled" onClick={handleSend} disabled={!inputValue.trim()}>Send</Button>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Row, 
  Text, 
  Icon, 
  Box
} from '@ggui-ai/design/primitives';

interface StockData {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: StockData[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * Stock Ticker Dashboard component displaying live market data.
 * Listens for 'ggui:agent-data' events for real-time updates.
 */
export default function StockTickerDashboard({ 
  stocks: initialStocks = [], 
  lastUpdated: initialLastUpdated 
}: Props) {
  const [stocks, setStocks] = useState<StockData[]>(initialStocks);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(initialLastUpdated);

  // Stream Contract: Listen for live agent data updates
  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      const data = customEvent.detail;
      if (data) {
        if (Array.isArray(data.stocks)) {
          setStocks(data.stocks);
        }
        if (data.lastUpdated) {
          setLastUpdated(data.lastUpdated);
        }
      }
    };

    // Use global listener for the stream contract
    if (typeof addEventListener !== 'undefined') {
      addEventListener('ggui:agent-data', handleAgentData);
      return () => removeEventListener('ggui:agent-data', handleAgentData);
    }
  }, []);

  const formatTime = (isoString?: string) => {
    if (!isoString) return '--:--:--';
    try {
      const date = new Date(isoString);
      if (isNaN(date.getTime())) return '--:--:--';
      return date.toLocaleTimeString([], { 
        hour: '2-digit', 
        minute: '2-digit', 
        second: '2-digit' 
      });
    } catch {
      return '--:--:--';
    }
  };

  return (
    <Container maxWidth="xl" style={{ padding: 'var(--ggui-spacing-6)' }}>
      <Stack gap={24}>
        {/* Header Section */}
        <Row justify="between" align="center" style={{ flexWrap: 'wrap', gap: 'var(--ggui-spacing-4)' }}>
          <Stack gap={4}>
            <Text variant="h2" weight="bold" color="var(--ggui-color-onSurface)">
              Market Watch
            </Text>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Live exchange data feed
            </Text>
          </Stack>
          <Box 
            style={{
              padding: 'var(--ggui-spacing-2) var(--ggui-spacing-4)',
              background: 'var(--ggui-color-surfaceVariant)',
              borderRadius: 'var(--ggui-shape-radius-full)',
              display: 'flex',
              alignItems: 'center'
            }}
          >
            <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant)">
              {"Last Updated: " + formatTime(lastUpdated)}
            </Text>
          </Box>
        </Row>

        {/* Responsive Grid Section */}
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
          gap: 'var(--ggui-spacing-4)',
          width: '100%'
        }}>
          {stocks.length > 0 ? (
            stocks.map((stock, index) => {
              const changeVal = stock.change ?? 0;
              const isPositive = changeVal >= 0;
              const statusColor = isPositive 
                ? 'var(--ggui-color-success, #2e7d32)' 
                : 'var(--ggui-color-error, #d32f2f)';

              const stockKey = stock.symbol ? stock.symbol : ("stock-" + index);

              return (
                <Card 
                  key={stockKey}
                  padding={20}
                  variant="outlined"
                  style={{
                    borderColor: statusColor,
                    transition: 'transform 0.2s ease, box-shadow 0.2s ease',
                    cursor: 'default'
                  }}
                >
                  <Stack gap={16}>
                    {/* Symbol and Price */}
                    <Row justify="between" align="start">
                      <Stack gap={2}>
                        <Text variant="h3" weight="bold" color="var(--ggui-color-onSurface)">
                          {stock.symbol || '---'}
                        </Text>
                        <Text 
                          variant="caption" 
                          color="var(--ggui-color-onSurfaceVariant)"
                          style={{ 
                            overflow: 'hidden', 
                            textOverflow: 'ellipsis', 
                            whiteSpace: 'nowrap',
                            maxWidth: '140px'
                          }}
                        >
                          {stock.name || 'Unknown Company'}
                        </Text>
                      </Stack>
                      <Text variant="h3" weight="bold" color="var(--ggui-color-onSurface)">
                        {"$" + (stock.price || 0).toFixed(2)}
                      </Text>
                    </Row>

                    {/* Change Statistics */}
                    <Row justify="end" align="center" gap={4}>
                      <Icon 
                        name={isPositive ? 'arrow-upward' : 'arrow-downward'} 
                        size={16} 
                        style={{ color: statusColor }}
                      />
                      <Text 
                        variant="body"
                        weight="semibold" 
                        style={{ color: statusColor }}
                      >
                        {(isPositive ? '+' : '') + changeVal.toFixed(2) + ' (' + (stock.changePercent || 0).toFixed(2) + '%)'}
                      </Text>
                    </Row>
                  </Stack>
                </Card>
              );
            })
          ) : (
            /* Loading Connection State */
            <Box 
              style={{ 
                gridColumn: '1 / -1',
                padding: 'var(--ggui-spacing-12)',
                background: 'var(--ggui-color-surfaceVariant)',
                borderRadius: 'var(--ggui-shape-radius-lg)',
                border: '1px dashed var(--ggui-color-outline)'
              }}
            >
              <Stack align="center" gap={16}>
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                  Waiting for market data connection...
                </Text>
                <div style={{
                  width: '32px',
                  height: '32px',
                  border: '3px solid var(--ggui-color-outline)',
                  borderTopColor: 'var(--ggui-color-primary)',
                  borderRadius: '50%',
                  animation: 'ggui-spin 1s linear infinite'
                }} />
              </Stack>
            </Box>
          )}
        </div>
      </Stack>

      <style>{"@keyframes ggui-spin { to { transform: rotate(360deg); } }"}</style>
    </Container>
  );
}

