import React, { useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
} from '@ggui-ai/design/primitives';

/**
 * Props Contract
 */
interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Action Contract: submit survey callback */
  onSubmit: (data: SurveyData) => void;
}

interface SurveyData {
  name: string;
  email: string;
  satisfaction: number | null;
  features: string[];
  comments: string;
}

/**
 * Multi-step Survey Form
 */
export default function SurveyForm(props: Props) {
  const { featureOptions = ['A', 'B'], satisfactionLabels = ['1', '2'], onSubmit } = props;
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<SurveyData>({
    name: '',
    email: '',
    satisfaction: null,
    features: [],
    comments: '',
  });

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);

  const handleSubmit = async () => {
    setIsSubmitting(true);
    try {
      if (onSubmit) await onSubmit(formData);
      setIsSubmitted(true);
    } catch (e) {
      console.error(e);
    } finally {
      setIsSubmitting(false);
    }
  };

  const currentPercent = String(Math.floor((step / 5) * 100)) + '%';

  if (isSubmitted) {
    return (
      <Card variant="flat" style={{ padding: 'var(--ggui-spacing-xl)' }}>
        <Text variant="heading-m">Success</Text>
        <Button variant="primary" onClick={() => setStep(1)}>New</Button>
      </Card>
    );
  }

  return (
    <Card 
      variant="elevated" 
      style={{ 
        maxWidth: '500px', 
        margin: 'var(--ggui-spacing-xl) auto',
        backgroundColor: 'var(--ggui-color-surface)'
      }}
    >
      <Stack padding="large" gap="small">
        <Text variant="label-s">Step {step} of 5</Text>
        <div style={{ height: '4px', background: 'var(--ggui-color-surface-container-high)' }}>
          <div style={{ height: '100%', width: currentPercent, background: 'var(--ggui-color-primary)' }} />
        </div>
      </Stack>

      <Stack padding="xl" gap="xl">
        {step === 1 && (
          <Stack gap="large">
            <Text variant="heading-s">Step 1</Text>
            <div>
              <Text as="label" htmlFor="name-input">Full Name</Text>
              <Input label="Full Name" id="name-input" value={formData.name} onChange={(v: string) => setFormData({...formData, name: v})} />
            </div>
            <div>
              <Text as="label" htmlFor="email-input">Email</Text>
              <Input label="Email" id="email-input" type="email" value={formData.email} onChange={(v: string) => setFormData({...formData, email: v})} />
            </div>
          </Stack>
        )}

        {step === 2 && (
          <Stack gap="large">
            <Text variant="heading-s">Step 2</Text>
            {satisfactionLabels.map((l, i) => (
              <label key={l} style={{ display: 'flex', gap: 'var(--ggui-spacing-medium)', padding: 'var(--ggui-spacing-medium)', border: '1px solid var(--ggui-color-outline)' }}>
                <input type="radio" checked={formData.satisfaction === (i+1)} onChange={() => setFormData({...formData, satisfaction: i+1})} />
                <Text variant="body-m">{l}</Text>
              </label>
            ))}
          </Stack>
        )}

        {step === 3 && (
          <Stack gap="large">
            <Text variant="heading-s">Step 3</Text>
            {featureOptions.map(f => (
              <label key={f} style={{ display: 'flex', gap: 'var(--ggui-spacing-medium)' }}>
                <input type="checkbox" checked={formData.features.includes(f)} onChange={() => setFormData(p => ({...p, features: p.features.includes(f) ? p.features.filter(x => x!==f) : [...p.features, f]}))} />
                <Text variant="body-m">{f}</Text>
              </label>
            ))}
          </Stack>
        )}

        {step === 4 && (
          <Stack gap="large">
            <Text variant="heading-s">Step 4</Text>
            <textarea 
              style={{ width: '100%', minHeight: '100px', padding: 'var(--ggui-spacing-medium)' }}
              value={formData.comments}
              onChange={(e) => setFormData({...formData, comments: e.currentTarget.value})}
              aria-label="Comments"
            />
          </Stack>
        )}

        {step === 5 && (
          <Stack gap="large">
            <Text variant="heading-s">Review</Text>
            <Text variant="body-s">Name: {formData.name}</Text>
            <Text variant="body-s">Email: {formData.email}</Text>
          </Stack>
        )}
      </Stack>

      <Stack direction="row" justify="space-between" padding="large">
        <Button variant="outline" onClick={() => setStep(step - 1)} disabled={step === 1}>Back</Button>
        {step < 5 ? (
          <Button variant="primary" onClick={() => setStep(step + 1)}>Next</Button>
        ) : (
          <Button variant="primary" onClick={handleSubmit} loading={isSubmitting}>Submit Survey</Button>
        )}
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import { Card, Stack, Text, Input, Button } from '@ggui-ai/design/primitives';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  electronConfiguration?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Array of elements with atomicNumber, symbol, name, atomicWeight, category (kebab-case), electronConfiguration, row, col */
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; electronConfiguration?: string; row?: number; col?: number }>;
}

const CATEGORY_COLORS: Record<string, string> = {
  'alkali-metal': 'var(--ggui-color-primary-100)',
  'alkaline-earth': 'var(--ggui-color-primary-200)',
  'transition-metal': 'var(--ggui-color-surface-variant)',
  'post-transition-metal': 'var(--ggui-color-neutral-100)',
  'metalloid': 'var(--ggui-color-secondary-100)',
  'nonmetal': 'var(--ggui-color-success-100)',
  'halogen': 'var(--ggui-color-warning-100)',
  'noble-gas': 'var(--ggui-color-error-50)',
  'lanthanide': 'var(--ggui-color-tertiary-100)',
  'actinide': 'var(--ggui-color-tertiary-200)',
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [q, setQ] = useState('');
  const [sel, setSel] = useState<ElementData | null>(null);

  const filtered = useMemo(() => {
    const term = q.toLowerCase().trim();
    if (!term) return elements;
    return elements.filter(e => {
      const n = e.name?.toLowerCase().includes(term);
      const s = e.symbol?.toLowerCase().includes(term);
      return n || s;
    });
  }, [elements, q]);

  const categories = Object.keys(CATEGORY_COLORS);

  return (
    <Stack gap="xl" style={{ padding: 'var(--ggui-spacing-lg)', width: '100%', margin: '0 auto' }}>
      <Stack gap="md">
        <Stack direction="row" justify="between" align="end" gap="lg" style={{ flexWrap: 'wrap' }}>
          <Stack gap="none">
            <Text variant="heading-lg" weight="bold">Periodic Table</Text>
            <Text variant="body-sm" style={{ color: 'var(--ggui-color-onSurface-variant)' }}>Chemical Element Explorer</Text>
          </Stack>
          <Stack gap="xs" style={{ width: '100%', maxWidth: '300px' }}>
            <Text as="label" htmlFor="search-input">Search Elements</Text>
            <Input label="Search Elements" id="search-input" placeholder="Search..." value={q} onChange={setQ} />
          </Stack>
        </Stack>

        <Stack direction="row" gap="md" style={{ flexWrap: 'wrap', padding: 'var(--ggui-spacing-xs)' }}>
          {categories.map((cat) => (
            <Stack key={cat} direction="row" align="center" gap="xs">
              <div style={{ width: 'var(--ggui-spacing-sm)', height: 'var(--ggui-spacing-sm)', borderRadius: 'var(--ggui-radius-xs)', backgroundColor: CATEGORY_COLORS[cat], border: '1px solid var(--ggui-color-outline-variant)' }} />
              <Text variant="body-xs" style={{ textTransform: 'capitalize' }}>{cat.replace(/-/g, ' ')}</Text>
            </Stack>
          ))}
        </Stack>
      </Stack>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(18, 1fr)', gap: 'var(--ggui-spacing-xs)', overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-lg)' }}>
        {filtered.map((el) => {
          const isSelected = sel?.atomicNumber === el.atomicNumber;
          const bg = el.category ? CATEGORY_COLORS[el.category] : 'var(--ggui-color-surface)';
          return (
            <div
              key={el.atomicNumber}
              onClick={() => setSel(el)}
              role="button"
              tabIndex={0}
              onKeyDown={(e) => { if (e.key === 'Enter') setSel(el); }}
              style={{
                gridColumn: el.col, gridRow: el.row, aspectRatio: '1/1',
                backgroundColor: bg,
                border: isSelected ? '2px solid var(--ggui-color-primary)' : '1px solid var(--ggui-color-outline-variant)',
                borderRadius: 'var(--ggui-radius-xs)',
                cursor: 'pointer', display: 'flex', flexDirection: 'column', padding: 'var(--ggui-spacing-xs)', position: 'relative',
                transform: isSelected ? 'scale(1.1)' : 'none', zIndex: isSelected ? 10 : 1, transition: 'transform 0.1s',
                boxShadow: isSelected ? 'var(--ggui-shadow-md)' : 'none'
              }}
              aria-label={el.name}
            >
              <Text variant="body-xs" style={{ fontSize: '0.6rem', position: 'absolute', top: 'var(--ggui-spacing-xs)', left: 'var(--ggui-spacing-xs)', color: 'var(--ggui-color-onSurface-variant)', lineHeight: 1 }}>{el.atomicNumber}</Text>
              <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                <Text variant="heading-sm" weight="bold" style={{ lineHeight: 1 }}>{el.symbol}</Text>
              </div>
            </div>
          );
        })}
      </div>

      {sel && (
        <Card variant="outlined" style={{ padding: 'var(--ggui-spacing-lg)' }}>
          <Stack gap="lg">
            <Stack direction="row" align="center" gap="lg">
              <div style={{ width: 'var(--ggui-spacing-3xl)', height: 'var(--ggui-spacing-3xl)', backgroundColor: sel.category ? CATEGORY_COLORS[sel.category] : 'var(--ggui-color-surface)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', borderRadius: 'var(--ggui-radius-sm)', border: '1px solid var(--ggui-color-outline)' }}>
                <Text variant="heading-md" weight="bold">{sel.symbol}</Text>
                <Text variant="body-xs">{sel.atomicNumber}</Text>
              </div>
              <Stack gap="none">
                <Text variant="heading-lg" weight="bold">{sel.name}</Text>
                <Text variant="body-sm" style={{ color: 'var(--ggui-color-onSurface-variant)', textTransform: 'capitalize' }}>{sel.category?.replace(/-/g, ' ')}</Text>
              </Stack>
            </Stack>
            <Stack direction="row" gap="xl" style={{ flexWrap: 'wrap' }}>
              <Stack gap="xs"><Text variant="body-xs" weight="bold">WEIGHT</Text><Text variant="body-md">{sel.atomicWeight} u</Text></Stack>
              <Stack gap="xs"><Text variant="body-xs" weight="bold">CONFIG</Text><Text variant="body-md">{sel.electronConfiguration}</Text></Stack>
            </Stack>
            <div style={{ textAlign: 'right' }}>
              <Button variant="ghost" size="sm" onClick={() => setSel(null)}>Dismiss Details</Button>
            </div>
          </Stack>
        </Card>
      )}
    </Stack>
  );
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  Stack, 
  Text, 
  Card, 
  Button, 
  Input, 
  Badge 
} from '@ggui-ai/design/primitives';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Array<Message>;
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function ChatInterface(props: Props) {
  const { title, currentUser, participantCount, messages: d = [], onSendMessage: c } = props;
  const [f, u] = useState<Message[]>(d);
  const [r, v] = useState('');
  const s = useRef<HTMLDivElement>(null);

  useEffect(() => { u(d); }, [d]);

  useEffect(() => {
    const e = (n: any) => {
      const l = n.detail;
      if (l?.text) u(k => [...k, l]);
    };
    addEventListener("ggui:agent-data", e);
    return () => removeEventListener("ggui:agent-data", e);
  }, []);

  useEffect(() => {
    if (s.current) s.current.scrollTop = s.current.scrollHeight;
  }, [f]);

  const x = useCallback(() => {
    if (!r.trim()) return;
    const e = new Date().toISOString();
    const n = { sender: currentUser, text: r, timestamp: e };
    u(l => [...l, n]);
    if (c) c({ text: r, timestamp: e });
    v("");
  }, [r, currentUser, c]);

  return (
    <Card variant="outlined" style={{ height: "500px", display: "flex", flexDirection: "column", width: "100%", maxWidth: "600px", margin: "0 auto", backgroundColor: "var(--ggui-color-surface)" }}>
      <Stack direction="row" align="center" justify="space-between" style={{ padding: "var(--ggui-spacing-md)", borderBottom: "1px solid var(--ggui-color-outlineVariant)" }}>
        <Stack direction="row" align="center" gap="sm">
          <Text variant="title-medium">{title}</Text>
          {participantCount !== void 0 && <Badge variant="secondary">{participantCount}</Badge>}
        </Stack>
      </Stack>

      <div ref={s} style={{ flex: 1, overflowY: "auto", padding: "var(--ggui-spacing-md)", display: "flex", flexDirection: "column", gap: "var(--ggui-spacing-xs)" }}>
        {f.map((e, n) => (
          <Stack key={n} align={e.sender === currentUser ? "end" : "start"} style={{ alignSelf: e.sender === currentUser ? "flex-end" : "flex-start", maxWidth: "80%", marginTop: "var(--ggui-spacing-sm)" }}>
            <Text variant="label-small">{e.sender}</Text>
            <Card variant="filled" style={{ padding: "var(--ggui-spacing-sm)", backgroundColor: e.sender === currentUser ? "var(--ggui-color-primary)" : "var(--ggui-color-surfaceVariant)", color: e.sender === currentUser ? "var(--ggui-color-onPrimary)" : "var(--ggui-color-onSurfaceVariant)" }}>
              <Text variant="body-medium" style={{ color: "inherit" }}>{e.text}</Text>
            </Card>
          </Stack>
        ))}
      </div>

      <Stack direction="row" gap="md" align="center" style={{ padding: "var(--ggui-spacing-md)", borderTop: "1px solid var(--ggui-color-outlineVariant)" }}>
        <Stack style={{ flex: 1 }}>
          <Text as="label" htmlFor="chat-input" variant="label-small">Message</Text>
          <Input label="Message" id="chat-input" value={r} onChange={v} onKeyDown={e => e.key === "Enter" && x()} fullWidth />
        </Stack>
        <Button variant="filled" onClick={x} disabled={!r.trim()}>Send</Button>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Text, 
  Heading, 
  Row, 
  Box,
  Divider,
  Badge,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface StockData {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  stocks: StockData[];
  lastUpdated?: string;
}

export default function StockTickerDashboard({ 
  stocks = [], 
  lastUpdated = new Date().toISOString() 
}: Props) {
  const [localStocks, setLocalStocks] = useState<StockData[]>(stocks);
  const [localUpdate, setLocalUpdate] = useState<string>(lastUpdated);
  const [isConnecting, setIsConnecting] = useState(stocks.length === 0);
  const { motionEnabled } = useMotion();

  useEffect(() => {
    if (stocks && stocks.length > 0) {
      setLocalStocks(stocks);
      setIsConnecting(false);
    }
    if (lastUpdated) {
      setLocalUpdate(lastUpdated);
    }
  }, [stocks, lastUpdated]);

  useEffect(() => {
    const handleAgentData = (event: any) => {
      const detail = event.detail || {};
      const data = detail.data;
      const timestamp = detail.timestamp;

      if (data && data.stocks) {
        setLocalStocks(data.stocks);
        setIsConnecting(false);
      }
      if (timestamp) {
        setLocalUpdate(timestamp);
      }
    };

    if (typeof addEventListener !== 'undefined') {
      addEventListener('ggui:agent-data', handleAgentData);
    }

    return () => {
      if (typeof removeEventListener !== 'undefined') {
        removeEventListener('ggui:agent-data', handleAgentData);
      }
    };
  }, []);

  const formatCurrency = (val?: number) => 
    (val ?? 0).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 });

  const formatPercent = (val?: number) => {
    const v = val ?? 0;
    const sign = v > 0 ? '+' : '';
    return sign + v.toFixed(2) + '%';
  };

  const formatTime = (iso?: string) => {
    try {
      if (!iso) return '---';
      const date = new Date(iso);
      return isNaN(date.getTime()) ? '---' : date.toLocaleTimeString();
    } catch (e) {
      return '---';
    }
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <MotionKeyframes />
      <Stack gap={24}>
        <Row justify="between" align="center" style={{ flexWrap: 'wrap', gap: 'var(--ggui-spacing-4)' }}>
          <Stack gap={4}>
            <Heading level={2}>Market Watch</Heading>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Live market monitoring active
            </Text>
          </Stack>
          <Stack align="end" gap={4}>
            <Badge variant={isConnecting ? 'warning' : 'success'}>
              {isConnecting ? 'Connecting...' : 'Live'}
            </Badge>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Last Updated: {formatTime(localUpdate)}
            </Text>
          </Stack>
        </Row>

        {localStocks.length === 0 && isConnecting ? (
          <Card padding={48}>
            <Stack align="center" gap={16}>
              <Box style={{ 
                width: 40, height: 40, 
                borderRadius: '50%', 
                border: '3px solid var(--ggui-color-primary-200)', 
                borderTopColor: 'var(--ggui-color-primary-600)',
                animation: 'ggui-spin 1s linear infinite'
              }} />
              <style>{`@keyframes ggui-spin { to { transform: rotate(360deg); } }`}</style>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                Connecting to live market stream...
              </Text>
            </Stack>
          </Card>
        ) : (
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
            gap: 'var(--ggui-spacing-4)',
            width: '100%',
          }}>
            {localStocks.map((stock, idx) => {
              const changeVal = stock.change ?? 0;
              const isPositive = changeVal >= 0;
              const colorToken = isPositive ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';
              const borderToken = isPositive ? 'var(--ggui-color-success-500)' : 'var(--ggui-color-error-500)';

              return (
                <Card 
                  key={stock.symbol || idx} 
                  padding={20}
                  variant="outlined"
                  style={{
                    borderColor: borderToken,
                    animation: motionEnabled ? animation.fadeIn : 'none',
                    animationDelay: (idx * 50) + 'ms',
                    transition: transition.colors,
                  }}
                >
                  <Stack gap={16}>
                    <Row justify="between" align="start">
                      <Stack gap={2}>
                        <Text weight="bold" style={{ fontSize: 'var(--ggui-font-size-2xl)' }}>
                          {stock.symbol || '---'}
                        </Text>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                          {stock.name || 'Company Name'}
                        </Text>
                      </Stack>
                      <Text weight="bold" style={{ fontSize: 'var(--ggui-font-size-xl)' }}>
                        {'$' + formatCurrency(stock.price)}
                      </Text>
                    </Row>
                    <Divider margin={0} />
                    <Row justify="between" align="center">
                      <Stack gap={4}>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                          24h Change
                        </Text>
                        <Row gap={4} align="center" style={{ color: colorToken }}>
                          <Text weight="semibold">
                            {(isPositive ? '▲ ' : '▼ ') + formatCurrency(Math.abs(changeVal))}
                          </Text>
                        </Row>
                      </Stack>
                      <Badge 
                        variant={isPositive ? 'success' : 'error'}
                        style={{ 
                          fontSize: 'var(--ggui-font-size-sm)',
                          fontWeight: 'var(--ggui-font-weight-bold)'
                        }}
                      >
                        {formatPercent(stock.changePercent)}
                      </Badge>
                    </Row>
                  </Stack>
                </Card>
              );
            })}
          </div>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Select,
  Checkbox,
  RadioGroup,
  Button,
  Divider,
  Box,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string };
  onComplete?: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const {
    avatarOptions = ['👤', '🚀', '🎨', '💼'],
    roleOptions = ['Developer', 'Designer', 'Manager', 'Other'],
    initialProfile = {},
    onComplete
  } = props;

  const { motionEnabled } = useMotion();
  const [currentStep, setCurrentStep] = useState(1);
  const [profile, setProfile] = useState({
    name: initialProfile.name || '',
    email: initialProfile.email || '',
    avatar: initialProfile.avatar || (avatarOptions && avatarOptions[0]) || '',
    role: initialProfile.role || '',
    emailNotifications: initialProfile.emailNotifications ?? true,
    theme: initialProfile.theme || 'light'
  });

  const updateField = (field: string, value: any) => {
    setProfile((prev) => ({ ...prev, [field]: value }));
  };

  const isStep1Valid = useMemo(() => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return profile.name.trim().length > 0 && emailRegex.test(profile.email) && profile.avatar !== '';
  }, [profile.name, profile.email, profile.avatar]);

  const isStep2Valid = useMemo(() => profile.role !== '', [profile.role]);

  const canGoNext = currentStep === 1 ? isStep1Valid : currentStep === 2 ? isStep2Valid : true;

  const handleNext = () => {
    if (currentStep < 3) setCurrentStep((s) => s + 1);
    else onComplete?.(profile);
  };

  const handleBack = () => { if (currentStep > 1) setCurrentStep((s) => s - 1); };

  const stepTitles: Record<number, string> = { 1: 'Profile Setup', 2: 'Preferences', 3: 'Review & Confirm' };

  const progressPercent = (currentStep / 3) * 100 + "%";

  return (
    <Container maxWidth="sm" padding={24}>
      <MotionKeyframes />
      <Stack gap={24}>
        <Card padding={24}>
          <Stack gap={24}>
            <Stack gap={8}>
              <Row justify="between" align="center">
                <Text variant="label" color="var(--ggui-color-onSurface)">Step {currentStep} of 3</Text>
                <Text variant="caption" weight="semibold">{stepTitles[currentStep]}</Text>
              </Row>
              <Box background="var(--ggui-color-surface-container)" borderRadius={4} style={{ height: 8, overflow: 'hidden' }}>
                <Box
                  background="var(--ggui-color-primary)"
                  style={{
                    height: '100%',
                    width: progressPercent,
                    transition: transition.transform
                  }}
                />
              </Box>
            </Stack>

            <Box style={{ animation: motionEnabled ? animation.fadeIn : 'none' }} key={currentStep}>
              {currentStep === 1 && (
                <Stack gap={16}>
                  <Stack gap={4}>
                    <Text as="label" htmlFor="name" variant="label">Full Name</Text>
                    <Input label="Full Name" id="name" value={profile.name} onChange={(v: string) => updateField('name', v)} required />
                  </Stack>
                  <Stack gap={4}>
                    <Text as="label" htmlFor="email" variant="label">Email Address</Text>
                    <Input label="Email Address" id="email" type="email" value={profile.email} onChange={(v: string) => updateField('email', v)} required />
                  </Stack>
                  <Stack gap={8}>
                    <Text variant="label">Choose Avatar</Text>
                    <Row gap={12} wrap>
                      {(avatarOptions || []).map((emoji) => (
                        <Button key={emoji} variant={profile.avatar === emoji ? 'primary' : 'outline'} onClick={() => updateField('avatar', emoji)} style={{ fontSize: '1.5rem', width: 56, height: 56, padding: 0 }} aria-label={emoji}>{emoji}</Button>
                      ))}
                    </Row>
                  </Stack>
                </Stack>
              )}

              {currentStep === 2 && (
                <Stack gap={20}>
                  <Select label="Role" id="role" placeholder="Select role" value={profile.role} onChange={(v: string) => updateField('role', v)} options={(roleOptions || []).map((r) => ({ value: r, label: r }))} required />
                  <Checkbox label="Email Notifications" id="notif" checked={profile.emailNotifications} onChange={(v: boolean) => updateField('emailNotifications', v)} />
                  <RadioGroup label="Theme Preference" value={profile.theme} onChange={(v: string) => updateField('theme', v)} direction="horizontal" options={[{ value: 'light', label: 'Light Mode' }, { value: 'dark', label: 'Dark Mode' }]} />
                </Stack>
              )}

              {currentStep === 3 && (
                <Stack gap={16}>
                  <Text variant="body" color="var(--ggui-color-onSurface-variant)">Review your information before completing the setup.</Text>
                  <Divider margin={8} />
                  <Stack gap={12}>
                    <Row justify="between"><Text weight="semibold">Name</Text><Text>{profile.name}</Text></Row>
                    <Row justify="between"><Text weight="semibold">Email</Text><Text>{profile.email}</Text></Row>
                    <Row justify="between"><Text weight="semibold">Avatar</Text><Text style={{ fontSize: '1.2rem' }}>{profile.avatar}</Text></Row>
                    <Row justify="between"><Text weight="semibold">Role</Text><Text>{profile.role}</Text></Row>
                    <Row justify="between"><Text weight="semibold">Notifications</Text><Text>{profile.emailNotifications ? 'Enabled' : 'Disabled'}</Text></Row>
                    <Row justify="between"><Text weight="semibold">Theme</Text><Text style={{ textTransform: 'capitalize' }}>{profile.theme}</Text></Row>
                  </Stack>
                  <Divider margin={8} />
                </Stack>
              )}
            </Box>

            <Row justify="between" padding={4}>
              {currentStep > 1 ? <Button variant="outline" onClick={handleBack}>Go Back</Button> : <Box />}
              <Button variant="primary" onClick={handleNext} disabled={!canGoNext}>{currentStep === 3 ? 'Complete Setup' : 'Next'}</Button>
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}
